class Solution(object):
    def expressiveWords(self, s, words):
        def is_stretchy(word):
            if len(word) > len(s):
                return False
            s_chars = [(s[0], 1)]
            for i in range(1, len(s)):
                if s[i] == s_chars[-1][0]:
                    s_chars[-1] = (s_chars[-1][0], s_chars[-1][1] + 1)
                else:
                    s_chars.append((s[i], 1))
            word_chars = [(word[0], 1)]
            for i in range(1, len(word)):
                if word[i] == word_chars[-1][0]:
                    word_chars[-1] = (word_chars[-1][0], word_chars[-1][1] + 1)
                else:
                    word_chars.append((word[i], 1))
            if len(s_chars) != len(word_chars):
                return False
            for (sc, sc_count), (wc, wc_count) in zip(s_chars, word_chars):
                if sc != wc or wc_count > sc_count or sc_count < 3 and sc_count != wc_count:
                    return False
            return True
        return sum(1 for word in words if is_stretchy(word))
